import { useState, useRef } from "react";
import { useNavigate } from "react-router-dom";
import "./verify.css";

export default function Verify() {
  const navigate = useNavigate();

  const [type, setType] = useState("mobile");
  const [otp, setOtp] = useState(["", "", "", "", "", ""]);
  const inputs = useRef([]);

  const handleChange = (value, index) => {
    if (!/^\d*$/.test(value)) return;

    const newOtp = [...otp];
    newOtp[index] = value.slice(-1);
    setOtp(newOtp);

    if (value && index < 5) {
      inputs.current[index + 1].focus();
    }
  };

  const handleVerify = () => {
    const code = otp.join("");

    if (code === "123456") {
      navigate("/verified", { state: { type } });
    } else {
      alert("Invalid OTP (use 123456)");
    }
  };

  return (
    <div className="container">
      <div className="card">
        <h2>Verify Your {type === "email" ? "Email" : "Mobile"}</h2>

        <div className="toggle">
          <button onClick={() => setType("mobile")}>Mobile</button>
          <button onClick={() => setType("email")}>Email</button>
        </div>

        <p className="subtext">Enter 6-digit code (123456)</p>

        <div className="otp-box">
          {otp.map((digit, i) => (
            <input
              key={i}
              ref={(el) => (inputs.current[i] = el)}
              value={digit}
              onChange={(e) => handleChange(e.target.value, i)}
              maxLength={1}
            />
          ))}
        </div>

        <button onClick={handleVerify}>
          Verify
        </button>
      </div>
    </div>
  );
}
